export function pickLectureTheme(week) {
  return LECTURE_THEMES.find(t => week >= t.weeks[0] && week <= t.weeks[1]) || LECTURE_THEMES[0];
}

// 时间随周递减 W1 95s → W30 65s,W37+ 60s
export function lectureTimeForWeek(week) {
  if (week >= 37) return 60;
  return Math.max(60, 95 - Math.max(0, week - 1) * 1.2 | 0);
}

// 连词方向逐级解锁:
//   tier 1 (W1-10):  只能横着连
//   tier 2 (W11-22): 横 + 竖
//   tier 3 (W23+):   横、竖、斜全 8 方向
export function lectureDirTier(week) {
  if (week <= 10) return 1;
  if (week <= 22) return 2;
  return 3;
}
export function lectureDirInfo(week) {
  const tier = lectureDirTier(week);
  if (tier === 1) return { tier, dirs: ['h'], label: '只能横着连', desc: '左右方向 · 入门' };
  if (tier === 2) return { tier, dirs: ['h', 'v'], label: '横 + 竖', desc: '上下也能连了' };
  return { tier, dirs: ['h', 'v', 'd'], label: '横 + 竖 + 斜', desc: '8 方向全开 · 高级' };
}
// 检查两 cell 是否合法相邻(按 tier 限制方向)
export function isLectureAdjacent(a, b, dirs) {
  if (!a || !b) return false;
  const dr = Math.abs(a.r - b.r);
  const dc = Math.abs(a.c - b.c);
  if (dr === 0 && dc === 0) return false;
  if (dr > 1 || dc > 1) return false;
  if (dr === 0 && dc === 1) return dirs.includes('h');
  if (dr === 1 && dc === 0) return dirs.includes('v');
  if (dr === 1 && dc === 1) return dirs.includes('d');
  return false;
}

// 单词得分:3 字母 = 1 · 4 = 2 · 5 = 4 · 6 = 7 · 7+ = 12
export function scoreWord(word, theme) {
  const len = word.length;
  let base = 0;
  if (len === 3) base = 1;
  else if (len === 4) base = 2;
  else if (len === 5) base = 4;
  else if (len === 6) base = 7;
  else if (len >= 7) base = 12;
  const isBonus = theme && theme.bonus.includes(word.toUpperCase());
  return { points: isBonus ? base * 2 : base, isBonus };
}

// academic 加成阶梯
export function lectureAcademic(score) {
  if (score >= 25) return 12;
  if (score >= 15) return 8;
  if (score >= 8)  return 4;
  return 1;
}

// 生成 10×10 字母网格 —— 中央 5×5 区域 bias 向 theme bias 字母,边角随机
const COMMON_LETTERS = 'ETAONIRSHDLUCMFGYPWBVKJXQZ';  // English letter frequency

export function generateLectureGrid(theme, rng = Math.random) {
  const grid = [];
  const biasPool = (theme.bias || '').toUpperCase().replace(/[^A-Z]/g, '');
  for (let r = 0; r < 10; r++) {
    const row = [];
    for (let c = 0; c < 10; c++) {
      const isCenter = r >= 2 && r <= 6 && c >= 2 && c <= 7;
      let ch;
      if (isCenter && biasPool && rng() < 0.55) {
        // 60% chance pick from theme bias letters
        ch = biasPool[Math.floor(rng() * biasPool.length)];
      } else {
        // Edge / fallback: English frequency-weighted random
        // Bias E/T/A/O/N more by indexing into early portion
        const idx = Math.floor(Math.pow(rng(), 1.5) * COMMON_LETTERS.length);
        ch = COMMON_LETTERS[idx];
      }
      row.push(ch);
    }
    grid.push(row);
  }
  return grid;
}
